import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Core Architecture","description":"OpenSIN core architecture overview","frontmatter":{"title":"Core Architecture","description":"OpenSIN core architecture overview"},"headers":[],"relativePath":"architecture/core.md","filePath":"architecture/core.md"}'),i={name:"architecture/core.md"};function s(n,e,c,l,h,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="core-architecture" tabindex="-1">Core Architecture <a class="header-anchor" href="#core-architecture" aria-label="Permalink to &quot;Core Architecture&quot;">​</a></h1><p>OpenSIN is built on a modular, extensible architecture.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><h3 id="queryengine" tabindex="-1">QueryEngine <a class="header-anchor" href="#queryengine" aria-label="Permalink to &quot;QueryEngine&quot;">​</a></h3><p>The heart of OpenSIN — manages the complete conversation lifecycle with async generators, ReAct loops, and token budget tracking.</p><h3 id="hook-system" tabindex="-1">Hook System <a class="header-anchor" href="#hook-system" aria-label="Permalink to &quot;Hook System&quot;">​</a></h3><p>Event-driven automation with 20+ events and 5 execution modes (shell, HTTP, function, agent, prompt).</p><h3 id="tool-system" tabindex="-1">Tool System <a class="header-anchor" href="#tool-system" aria-label="Permalink to &quot;Tool System&quot;">​</a></h3><p>Rich tool interface with 8+ built-in tools, deferred loading, and permission-aware filtering.</p><h3 id="permission-system" tabindex="-1">Permission System <a class="header-anchor" href="#permission-system" aria-label="Permalink to &quot;Permission System&quot;">​</a></h3><p>Multi-source permission rules with 6 modes and auto-mode classifier.</p><h3 id="subagent-system" tabindex="-1">Subagent System <a class="header-anchor" href="#subagent-system" aria-label="Permalink to &quot;Subagent System&quot;">​</a></h3><p>Fork pattern with cache-identical prefixes for maximum cache hits.</p><h3 id="mcp-client" tabindex="-1">MCP Client <a class="header-anchor" href="#mcp-client" aria-label="Permalink to &quot;MCP Client&quot;">​</a></h3><p>Multi-transport support (stdio, SSE, HTTP, WS, in-process).</p><h3 id="sandbox" tabindex="-1">Sandbox <a class="header-anchor" href="#sandbox" aria-label="Permalink to &quot;Sandbox&quot;">​</a></h3><p>Filesystem and network rules with git escape prevention.</p><h3 id="memory-system" tabindex="-1">Memory System <a class="header-anchor" href="#memory-system" aria-label="Permalink to &quot;Memory System&quot;">​</a></h3><p>File-based memory with SIN.md auto-discovery and session extraction.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/architecture/a2a.html">A2A Protocol</a></li><li><a href="/architecture/security.html">Security</a></li></ul>',21)])])}const p=t(i,[["render",s]]);export{u as __pageData,p as default};
